import os
import sqlite3

# Database connection
conn = sqlite3.connect('permissions.db')
cursor = conn.cursor()

def get_file_contents(file_path, user):
    # Check user permission in the database
    cursor.execute("SELECT permission FROM users WHERE username = ?", (user,))
    permission = cursor.fetchone()[0]

    # Open and return file contents if permission granted
    if permission == 'read':
        with open(file_path, 'r') as f:
            return f.read()
    else:
        raise PermissionError("User does not have read permission.")